INSERT INTO agent_skill_learnings (agent_id, skill_id, content) VALUES
-- @maykon (6 learnings)
('maykon', 'skill-copywriting', 'Roteiros devem soar naturais, como uma conversa com o publico. Evitar frases curtas sem conexao entre si — o texto precisa fluir.'),
('maykon', 'skill-copywriting', 'Variar estruturas de roteiro entre pecas. Todos seguirem o mesmo formato passa impressao de robotizado e sem criatividade.'),
('maykon', 'skill-copywriting', 'Headlines e textos de apoio precisam de variedade de estilos. Nao repetir a mesma estrutura em todas as pecas.'),
('maykon', 'skill-copywriting', 'NUNCA informar valores monetarios especificos na legenda (exceto padroes publicos como % de impostos). Risco de propaganda enganosa.'),
('maykon', 'skill-copywriting', 'NUNCA usar cases "reais" com numeros inventados — pode ser enquadrado como propaganda enganosa. Se usar simulacao, deixar explicito.'),
('maykon', 'skill-copywriting', 'Nao incluir "Assinatura" nos posts. Desnecessario.'),
-- @iza (2 learnings)
('iza', 'skill-content-briefing', 'Quando peca coincide com data comemorativa, equilibrar tema tecnico com gancho da data no mesmo conteudo. Nao separar em duas pecas.'),
('iza', 'skill-content-briefing', 'Evitar excesso de pecas com mesmo angulo emocional no mesmo mes (ex: varias pecas "mae protege filhos"). Distribuir angulos com variedade.'),
-- @argos (3 learnings)
('argos', 'skill-content-qa', 'Vetar tom agressivo ou que fale negativamente sobre outros profissionais do mesmo nicho.'),
('argos', 'skill-content-qa', 'Vetar legendas que abrem com primeira frase cliche. Exigir hook original.'),
('argos', 'skill-content-qa', 'Vetar roteiros sem profundidade — temas "corridos" que nao desenvolvem o assunto. Exigir aprofundamento ou sugerir complemento (ex: caixinha de perguntas nos stories).'),
-- @rapha (2 learnings)
('rapha', 'skill-content-architecture', 'Sugerir formatos criativos variados por peca (ex: checklist visual para "sinais", comparativo lado-a-lado, caixinha de perguntas como complemento nos stories).'),
('rapha', 'skill-content-architecture', 'Considerar pessoalidade do cliente — perguntar sobre referencias pessoais (inspiracao familiar, historia) para conteudo mais autentico e emocional.');
